const GRADED_TIERS = ['PSA 10', 'BGS 10 BL', 'BGS 10', 'CGC 10', 'ARS 10'];

function isGradedTier(tier) {
  return GRADED_TIERS.includes(tier) || /^(PSA|BGS|CGC|ARS)\b/.test(tier || '');
}

