          {source === 'swibswap' && (
            <>Coming soon — <strong>SwibSwap.com</strong> direct trades, available when the internal market launches.</>
          )}
        </div>
      )}

      {source === 'current' && (
        <>
          <div style={{ display: 'flex', gap: 6, marginBottom: 10 }}>
            {sortBtn('price_desc', 'Price ↓')}
            {sortBtn('price_asc',  'Price ↑')}
          </div>
          <div style={{ fontSize: SZ.sm, fontFamily: T.fontMono }}>
            <div style={{
              display: 'grid', gridTemplateColumns: '70px 1fr 80px',
              padding: '8px 4px', color: T.textLow, fontSize: SZ.xs,
              borderBottom: `1px solid ${T.border}`, letterSpacing: '0.05em', fontWeight: 600,
              gap: 8,
            }}>
              <div>GRADE</div><div>LISTING</div><div style={{ textAlign: 'right' }}>PRICE</div>
            </div>
            {sorted.map((it, i) => {
              // SCN54 — re-classify from the title every time (don't trust
              // conditionTier from the eBay payload — it's frequently stale
              // or set to "Raw" for everything). Run the regex against the
              // padded uppercase form so it actually fires at title edges.
              // SCN78 — Extract the ACTUAL graded value from the title.
              // Top-tier 10s first (most common), then any lower PSA / BGS /
              // CGC / ARS / GMA / AGS / TAG / HGA / SGC grade. Anything not
              // graded → 'RAW'. No more "Lower" placeholder.
              const upperTitle = ` ${String(it.title || '').toUpperCase()} `;
              let tier;
              const psa10 = /[^A-Z]PSA[\s.-]*10[^0-9]/.test(upperTitle);
              const bgs10bl = /[^A-Z]BGS[\s.-]*10\s*BL/.test(upperTitle);
              const bgs10 = /[^A-Z]BGS[\s.-]*10[^0-9]/.test(upperTitle);
              const cgc10 = /[^A-Z]CGC[\s.-]*10[^0-9]/.test(upperTitle);
              const ars10 = /[^A-Z]ARS[\s.-]*10[^0-9]/.test(upperTitle);
              if (psa10)         tier = 'PSA 10';
              else if (bgs10bl)  tier = 'BGS 10 BL';
              else if (bgs10)    tier = 'BGS 10';
              else if (cgc10)    tier = 'CGC 10';
              else if (ars10)    tier = 'ARS 10';
              else {
                // Lower-grade match — extract the actual numeric grade.
                const lowerMatch = upperTitle.match(/\b(PSA|BGS|CGC|ARS|GMA|AGS|TAG|HGA|SGC)\b[\s.-]*(\d+(?:\.\d)?)/);
                if (lowerMatch) tier = `${lowerMatch[1]} ${lowerMatch[2]}`;
                else tier = 'Raw';
              }
              const isGraded = tier !== 'Raw';
              // RAW everywhere for non-graded rows. Graded rows show the
              // actual grade detected from the title (PSA 10 / PSA 9.5 / etc).
              const gradeLabel = isGraded ? tier.toUpperCase() : 'RAW';
              // Strip noisy boilerplate from titles so the row reads cleanly.
              const cleanTitle = String(it.title || '')
                .replace(/\b(NEW|MINT|HOT|RARE|TCG|CCG|FREE\s*SHIP\w*|FAST\s*SHIP\w*|US\s*SELLER)\b/gi, '')
                .replace(/\s{2,}/g, ' ').trim();
              return (
                <a
                  key={i} href={it.url} target="_blank" rel="noopener noreferrer"
                  style={{
                    display: 'grid', gridTemplateColumns: '70px 1fr 80px',
                    padding: '10px 4px', borderBottom: `1px solid ${T.border}`,
                    color: T.textMid, textDecoration: 'none',
                    gap: 8, alignItems: 'center',
                  }}
                  title={it.title}
                >
                  <div style={{
                    fontSize: 10, fontWeight: 700,
                    color: isGraded ? T.cyan : T.textMid,
                    fontFamily: T.fontDisplay, letterSpacing: '0.03em',
                    whiteSpace: 'nowrap',
                  }}>{gradeLabel}</div>
                  <div style={{
                    color: T.textMid, fontSize: SZ.xs, lineHeight: 1.35,
                    overflow: 'hidden',
                    display: '-webkit-box',
                    WebkitLineClamp: 2,
                    WebkitBoxOrient: 'vertical',
                    textOverflow: 'ellipsis',
                    wordBreak: 'break-word',
                  }}>{cleanTitle || cardLabel || 'eBay listing'}</div>
                  <div style={{
                    textAlign: 'right', color: T.textHi,
                    fontWeight: 700, fontSize: SZ.sm,
                  }}>
                    {fmt(it.priceUSD)}
                  </div>
                </a>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
}

// Bar chart — average price per tier (Raw / PSA10 / BGS10 / etc.).
// SCN45 — Single hero tile with toggle between RAW · NEAR MINT and PSA 10.
// Shows sold-only data: median (hero), low → high range, sample count,
// last sold price + date. Replaces the older multi-tier bar chart —
// fewer data points, each gets the visual weight it deserves.
// SCN53 — Side-by-side tiles: PSA 10 (left) and RAW · NEAR MINT (right).
// Sold-only median / range / sample count / last sold for each tier.
// Replaces the SCN45 toggle UI — both tiers are visible simultaneously.
function CurrentValueHero({ allItems, fmt }) {
  // Bucket every listing into PSA 10 / Raw NM. BGS10/CGC10/lower grades
  // are excluded — they still appear in TradingHistory below.
  const { raw, psa10 } = useMemo(() => {
    const rawArr = [];
    const psa10Arr = [];
    for (const it of allItems) {
      const tier = it.conditionTier || classifyTitleClient(it.title);
      const title = ` ${String(it.title || '').toUpperCase()} `;
      if (tier === 'PSA 10' || /[^A-Z]PSA[\s.-]*10[^0-9]/.test(title)) {
        psa10Arr.push(it);
      } else if (tier === 'Raw') {
        rawArr.push(it);
      }
    }
    return { raw: rawArr, psa10: psa10Arr };
  }, [allItems]);

  const computeStats = (items) => {
    const prices = items.map((it) => it.priceUSD).filter((p) => p > 0).sort((a, b) => a - b);
    if (prices.length === 0) return null;
    const mid = Math.floor(prices.length / 2);
    const median = prices.length % 2 ? prices[mid] : (prices[mid - 1] + prices[mid]) / 2;
    const dated = items.filter((it) => it.soldDate)
      .sort((a, b) => new Date(b.soldDate) - new Date(a.soldDate));
    return {
      median,
      low:  prices[0],
      high: prices[prices.length - 1],
      count: prices.length,
      lastSold: dated[0] || items[0],
    };
  };

  const psaStats = useMemo(() => computeStats(psa10), [psa10]);
  const rawStats = useMemo(() => computeStats(raw),   [raw]);

  if (!psaStats && !rawStats) return null;

  const renderTile = (label, accent, stats) => {
    const color = accent === 'cyan' ? T.cyan : T.magenta;
    const gradient = accent === 'cyan' ? T.gradientPrimary : T.magenta;
    return (
      <div style={{
        flex: 1, minWidth: 0,
        background: T.surface2,
        border: `1px solid ${T.border2}`,
        borderRadius: 14,
        padding: '14px 14px',
        position: 'relative', overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', top: 0, left: 0, right: 0, height: 3,
          background: gradient,
        }} />
        <div style={{
          fontSize: SZ.xs, color: T.textLow, fontFamily: T.fontDisplay,
          fontWeight: 700, letterSpacing: '0.06em',
        }}>
          {label}
        </div>

        {stats ? (
          <>
            <div style={{
              fontSize: 28, fontWeight: 700, fontFamily: T.fontDisplay,
              color, lineHeight: 1.1, marginTop: 4,
              letterSpacing: '-0.01em',
              whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis',
            }}>
              {fmt(stats.median)}
            </div>
            <div style={{
              fontSize: 10, color: T.textDim, fontFamily: T.fontMono,
              marginTop: 2, display: 'flex', gap: 6, alignItems: 'center',
            }}>
              <span>median</span><span>·</span><span>{stats.count} sold</span>
            </div>

            {stats.low !== stats.high && (
              <div style={{ marginTop: 10 }}>
                <div style={{
                  position: 'relative', height: 6, background: T.bgDeep,
                  borderRadius: 999, overflow: 'visible',
                }}>
                  <div style={{
                    position: 'absolute', inset: 0,
                    background: `linear-gradient(90deg, ${color}33, ${color})`,
                    borderRadius: 999,
                  }} />
                  <div style={{
                    position: 'absolute',
                    left: `${((stats.median - stats.low) / (stats.high - stats.low)) * 100}%`,
                    top: -2, bottom: -2,
                    width: 2, background: T.textHi,
                    borderRadius: 2, transform: 'translateX(-50%)',
                  }} />
                </div>
                <div style={{
                  display: 'flex', justifyContent: 'space-between',
                  marginTop: 4, fontSize: 10, color: T.textLow,
                  fontFamily: T.fontMono,
                }}>
                  <span>{fmt(stats.low)}</span>
                  <span>{fmt(stats.high)}</span>
                </div>
              </div>
            )}

            {stats.lastSold && (
              <div style={{
                marginTop: 10, paddingTop: 8,
                borderTop: `1px solid ${T.border}`,
                fontSize: 10, color: T.textLow, fontFamily: T.fontMono,
                display: 'flex', justifyContent: 'space-between', gap: 6,
              }}>
                <span>last sold</span>
                <span style={{ color: T.textHi, fontWeight: 600 }}>
                  {fmt(stats.lastSold.priceUSD)}
                </span>
              </div>
            )}
          </>
        ) : (
          <div style={{
            fontSize: SZ.xs, color: T.textDim,
            marginTop: 8, padding: '14px 0', textAlign: 'center',
          }}>
            No sales found
          </div>
        )}
      </div>
    );
  };

  return (
    <div style={{ marginTop: 18 }}>
      <SectionLabel>CURRENT VALUE · BY GRADE</SectionLabel>
      <div style={{ display: 'flex', gap: 10, marginTop: 10 }}>
        {renderTile('PSA 10', 'cyan', psaStats)}
        {renderTile('RAW · NEAR MINT', 'magenta', rawStats)}
      </div>
    </div>
  );
}


function classifyTitleClient(title) {
  // Mirrors the server classifier — top-tier grades only; everything else falls
  // into "Lower grades" or "Raw" so the condition tabs stay focused.
  const t = ` ${String(title || '').toUpperCase()} `;
  if (/[^A-Z]PSA[\s.-]*10[^0-9]/.test(t)) return 'PSA 10';
  if (/[^A-Z]BGS[\s.-]*10\s*BL/.test(t))  return 'BGS 10 BL';
  if (/[^A-Z]BGS[\s.-]*10[^0-9]/.test(t)) return 'BGS 10';
  if (/[^A-Z]CGC[\s.-]*10[^0-9]/.test(t)) return 'CGC 10';
  if (/[^A-Z]ARS[\s.-]*10[^0-9]/.test(t)) return 'ARS 10';
  if (/\b(PSA|BGS|CGC|ARS|GMA|AGS|TAG|HGA|SGC)\b[\s.-]*\d/.test(t)) return 'Lower grades';
  return 'Raw';
}

// Sold-price sparkline. Each point is a real sold listing — when a date
// is missing we fall back to index order so the graph still renders.
function Sparkline({ items, convert }) {
  if (!items || items.length < 2) return null;
  // Bucket: items WITH dates go first (sorted by date), then items without.
  // For the X axis we synthesize an index for everything; for items that
  // do have a date we keep them in their chronological position.
  const withDate = items.filter((it) => it.soldDate)
    .sort((a, b) => new Date(a.soldDate) - new Date(b.soldDate));
  const withoutDate = items.filter((it) => !it.soldDate);
  const sorted = [...withDate, ...withoutDate];
  const W = 480, H = 70, pad = 4;
  const ys = sorted.map((it) => convert ? convert(it.priceUSD) : it.priceUSD);
  const max = Math.max(...ys);
  const min = Math.min(...ys);
  const range = max - min || 1;
  const xs = sorted.map((_, i) => pad + (i / (sorted.length - 1)) * (W - pad * 2));
  const points = sorted.map((_, i) => {
    const y = H - pad - ((ys[i] - min) / range) * (H - pad * 2);
    return `${xs[i].toFixed(1)},${y.toFixed(1)}`;
  });
  return (
    <svg width="100%" height={H} viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none"
         style={{ display: 'block' }}>
      <defs>
        <linearGradient id="sparkfill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={T.cyan} stopOpacity="0.45"/>
          <stop offset="100%" stopColor={T.cyan} stopOpacity="0"/>
        </linearGradient>
      </defs>
      <polyline
        points={`${pad},${H - pad} ${points.join(' ')} ${W - pad},${H - pad}`}
        fill="url(#sparkfill)" stroke="none"
      />
      <polyline points={points.join(' ')} fill="none" stroke={T.cyan} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
      {/* Dots — magenta for items missing a date, cyan for dated items */}
      {sorted.map((it, i) => {
        const x = xs[i];
        const y = H - pad - ((ys[i] - min) / range) * (H - pad * 2);
        return <circle key={i} cx={x} cy={y} r="2.5" fill={it.soldDate ? T.cyan : T.magenta} />;
      })}
    </svg>
  );
}

